const input = $input.first().json || {};
if (input.relay?.validated_by_api === true) {
  return $input.all();
}
throw new Error('Direct Meta traffic not supported in this workflow. Route Instagram status webhooks through NovaVision API /webhooks/instagram.');

const body = $input.first().json.body || $input.first().json;
const entry = body?.entry?.[0] || {};
const messaging = entry?.messaging?.[0] || null;
const delivery = messaging?.delivery || null;
const read = messaging?.read || null;
const message = delivery || read || null;
if (!message) return [{ json: { is_supported_event: false } }];
const mids = message.mids || [];
return mids.map(mid => ({ json: {
  is_supported_event: true,
  channel: 'INSTAGRAM',
  provider: 'META',
  provider_message_id: mid,
  delivery_status: read ? 'READ' : 'DELIVERED',
  event_at: new Date(message.watermark || Date.now()).toISOString(),
  raw_payload: messaging
} }));
